queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?name ?othercolumn1 WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:TerritoryID ?cg . ?child a :Territories ; p:RegionID ?cg . ?l p:SalesRepID ?pg . ?parent a :Sales_Representatives ; p:ID ?pg . } GROUP BY ?child }
  ?child p:name ?name .
  ?child p:OtherColumn1 ?othercolumn1 .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Sales_Representatives } }
  FILTER(?nf = ?total)
}

